def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        complexity_factor = 1 + np.sin(ratio * np.pi * 3) * 0.3
        if ratio < 0.05:
            for a in range(1, 15):
                temp = (np.cos(ratio * a * 5) + 1.5) * (a ** 2) * np.exp(-ratio * a / 1.5)
                if (a * i) % 4 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.1
                score += temp
            if (capacity % 4 == 0) and ((item * 7) % 2 == 0):
                score *= 0.79
            if score > 20:
                score /= (np.log1p(score) + 1)
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, min(int(capacity) + 3, 50)):
                val = ratio + np.sin(n) / (n + 1)
                prod *= val if val > 0 else 0.1
                if prod > 5e7:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod) % 500
            score += np.sqrt(ratio * mod_val + 2) * complexity_factor
            if (int(capacity * 2) % 8 == 0) or ((int(item * 5) + i) % 4 == 0):
                score += 6.7
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 3.2)
            score += extra_sum / 7
        elif 0.25 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                if m % 2 == 0:
                    increment *= 1.1
                else:
                    increment *= 0.95
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.6
                for k in range(1, int(remainder) + 1):
                    score += np.tanh(k / 3) * 0.7
            else:
                score -= remainder * 1.1
                if score < -8:
                    score = abs(score) * 0.25 + 3
            if int(capacity) % 5 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 15):
                term = ((ratio - 0.5) ** p) * (p ** 1.7) * np.sin(p * 0.3 + ratio)
                if abs(term) > 400:
                    term = np.sign(term) * (np.sqrt(abs(term)) + 10)
                penalty_base += term
                if abs(penalty_base) > 250:
                    penalty_base = np.log1p(abs(penalty_base)) * np.sign(penalty_base)
                    break
            score = penalty_base * 10 * complexity_factor
            if capacity < item * 1.1:
                score += 25
            if (int(capacity * 4) % 9 == 0) and (int(item * 11) % 7 == 0):
                score -= 8
            if score < -10:
                score *= -1.6
                score += 7
            if score > 120:
                score = 120
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 16):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.5) * np.cos(q * 0.7)
            score = penalty_ext * 18 * complexity_factor
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 3 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 2)
            if score < -12:
                score = abs(score) * 0.6
            if score > 1500:
                score = 1500
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 20):
                term = ((diff) ** r) * (r ** 3.5)
                if r % 4 == 0:
                    term *= 0.9
                if term > 20000:
                    term = np.sqrt(term) + np.log1p(term)
                super_penalty += term
            score = super_penalty * 20 + np.sin(ratio * np.pi) * 15
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 17) % 5 == 0) and (int(item * 23) % 6 == 0):
                score -= 16
            for w in range(3, 11):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3000:
                score = 3000
        else:
            ultra_penalty = 0
            diff = ratio - 2.0
            for t in range(1, 25):
                term = ((diff) ** t) * (t ** 4)
                if term > 25000:
                    term = np.log1p(term) * np.sqrt(term)
                ultra_penalty += term
            score = ultra_penalty * 30 + np.tanh(diff) * 50
            if capacity < item * 3:
                score += 40
            if (int(capacity * 19) % 7 == 0) and (int(item * 29) % 8 == 0):
                score -= 20
            for y in range(4, 13):
                score += ((diff / y) % 1) * (y * 3)
            if score < 0:
                score = abs(score) * 0.8 + 7
            if score > 4000:
                score = 4000
        if capacity > 300:
            adj = np.log1p(capacity * 1.5) + 2
            score /= adj
            if int(capacity) % 10 == 0:
                score *= 0.85
        elif capacity < 10:
            score *= 2.5
            if capacity < 3:
                score *= 1.2
        if np.isnan(score) or np.isinf(score):
            score = 0
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (10 + top_count * 1.5) - median_val * 0.9
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    max_abs = np.max(np.abs(priorities[np.isfinite(priorities)])) if priorities.size > 0 else 1
    if max_abs > 0:
        priorities = priorities / max_abs * 1000
    return priorities
